import sys

def solve():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    M = int(data[1])

    rows = set()
    cols = set()
    diag1 = set()  # i + j
    diag2 = set()  # i - j

    idx = 2
    for _ in range(M):
        a = int(data[idx]); b = int(data[idx+1])
        idx += 2
        rows.add(a)
        cols.add(b)
        diag1.add(a + b)
        diag2.add(a - b)

    # Count squares attacked by existing pieces
    attacked = 0

    # Rows
    attacked += len(rows) * N
    # Columns
    attacked += len(cols) * N
    # Diagonals (i + j constant)
    for s in diag1:
        # i + j = s, 1 <= i <= N, 1 <= j <= N
        # i ranges from max(1, s - N) to min(N, s - 1)
        low = max(1, s - N)
        high = min(N, s - 1)
        if low <= high:
            attacked += (high - low + 1)
    # Diagonals (i - j constant)
    for d in diag2:
        # i - j = d, 1 <= i <= N, 1 <= j <= N
        # i ranges from max(1, 1 + d) to min(N, N + d)
        low = max(1, 1 + d)
        high = min(N, N + d)
        if low <= high:
            attacked += (high - low + 1)

    # Remove double-counted intersections
    # Row ∩ Column
    attacked -= len(rows) * len(cols)
    # Row ∩ Diag1
    for a in rows:
        for s in diag1:
            # i = a, i + j = s → j = s - a
            if 1 <= s - a <= N:
                attacked -= 1
    # Row ∩ Diag2
    for a in rows:
        for d in diag2:
            # i = a, i - j = d → j = a - d
            if 1 <= a - d <= N:
                attacked -= 1
    # Column ∩ Diag1
    for b in cols:
        for s in diag1:
            # j = b, i + j = s → i = s - b
            if 1 <= s - b <= N:
                attacked -= 1
    # Column ∩ Diag2
    for b in cols:
        for d in diag2:
            # j = b, i - j = d → i = d + b
            if 1 <= d + b <= N:
                attacked -= 1
    # Diag1 ∩ Diag2
    for s in diag1:
        for d in diag2:
            # i + j = s, i - j = d → 2i = s + d, 2j = s - d
            if (s + d) % 2 == 0 and (s - d) % 2 == 0:
                i = (s + d) // 2
                j = (s - d) // 2
                if 1 <= i <= N and 1 <= j <= N:
                    attacked -= 1

    # Add back triple intersections
    # Row ∩ Column ∩ Diag1
    for a in rows:
        for b in cols:
            s = a + b
            if s in diag1:
                attacked += 1
    # Row ∩ Column ∩ Diag2
    for a in rows:
        for b in cols:
            d = a - b
            if d in diag2:
                attacked += 1
    # Row ∩ Diag1 ∩ Diag2
    for a in rows:
        for s in diag1:
            for d in diag2:
                # i = a, i + j = s, i - j = d
                if a + (s - a) == s and a - (a - d) == d:
                    j1 = s - a
                    j2 = a - d
                    if j1 == j2 and 1 <= j1 <= N:
                        attacked += 1
    # Column ∩ Diag1 ∩ Diag2
    for b in cols:
        for s in diag1:
            for d in diag2:
                # j = b, i + j = s, i - j = d
                i1 = s - b
                i2 = d + b
                if i1 == i2 and 1 <= i1 <= N:
                    attacked += 1

    # Subtract quadruple intersection (Row ∩ Column ∩ Diag1 ∩ Diag2)
    for a in rows:
        for b in cols:
            s = a + b
            d = a - b
            if s in diag1 and d in diag2:
                attacked -= 1

    # Total squares
    total_squares = N * N
    # Occupied squares
    occupied = M
    # Safe squares = total - occupied - (attacked - occupied) because attacked includes occupied squares
    safe = total_squares - attacked

    print(safe)

if __name__ == "__main__":
    solve()
